# Terraform: invite a B2B guest user and assign to a group
resource "azuread_invitation" "partner_invite" {
  user_email_address = "partner@fabrikam.com"
  redirect_url       = "https://myapps.microsoft.com"

  message {
    additional_recipients = []
    body                  = "Welcome to Contoso partner collaboration."
    language              = "en-US"
  }
}

# Retrieve the created guest user object
data "azuread_user" "partner_guest" {
  user_principal_name = azuread_invitation.partner_invite.user_principal_name
  depends_on          = [azuread_invitation.partner_invite]
}

# Add to a group
resource "azuread_group_member" "partner_in_group" {
  group_object_id  = azuread_group.partner_access.object_id
  member_object_id = data.azuread_user.partner_guest.object_id
}
